import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

/**
 * Generic transformation to fix breaking changes in jcabi-aspects Loggable annotation.
 * This transformation fixes calls to Loggable annotation with deprecated constructor parameters.
 * 
 * The breaking change in jcabi-aspects 0.25.1 likely involved changing the Loggable annotation
 * from accepting a simple integer level to requiring a specific enum or constant reference.
 * This transformation will handle both cases: updating the integer value to the proper enum reference
 * and ensuring the annotation is used correctly.
 */
public class Main {
    public static void main(String[] args) {
        // Check if source directory is provided
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDir = args[0];

        // Create Spoon launcher
        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDir);
        launcher.setSourceOutputDirectory(sourceDir + "/generated");
        launcher.getEnvironment().setComplianceLevel(8);

        // Process the code
        CtModel model = launcher.buildModel();

        // Find all Loggable annotations and fix them
        model.getElements(new TypeFilter<>(CtAnnotation.class))
            .stream()
            .filter(annotation -> annotation.getAnnotationType().getSimpleName().equals("Loggable"))
            .forEach(annotation -> {
                // Get the annotation type
                CtTypeReference<?> annotationType = annotation.getAnnotationType();

                // If it's a Loggable annotation, check its arguments
                if (annotationType.getQualifiedName().equals("com.jcabi.aspects.Loggable")) {
                    // Fix the Loggable annotation by replacing deprecated usage patterns
                    fixLoggableAnnotation(annotation);
                }
            });

        // Write the modified code back
        launcher.writeProcessedSourceFiles();

        System.out.println("Transformation completed successfully.");
    }

    /**
     * Fix Loggable annotation by updating deprecated usage patterns
     * 
     * The breaking change in jcabi-aspects 0.25.1 likely involved changing the Loggable annotation
     * from accepting a simple integer level to requiring a specific enum or constant reference.
     * This transformation will:
     * 1. Replace integer constants with the proper enum constant references
     * 2. Ensure the annotation is used with the correct parameter type
     */
    private static void fixLoggableAnnotation(CtAnnotation<?> annotation) {
        try {
            // Get the annotation values
            List<Object> values = annotation.getValues();

            // If there are values, check if we need to update them
            // The most common breaking change is changing from integer level to enum
            if (!values.isEmpty() && values.get(0) instanceof Integer) {
                // This is the most likely breaking change: integer level parameter
                // was replaced with enum constant
                Integer level = (Integer) values.get(0);

                // Map the integer level to the appropriate constant
                // Based on the API spec, Loggable has constants: DEBUG, ERROR, INFO, TRACE, WARN
                // We'll convert the integer to the corresponding constant
                String constantName = "DEBUG";
                switch (level) {
                    case 0: constantName = "TRACE"; break;
                    case 1: constantName = "DEBUG"; break;
                    case 2: constantName = "INFO"; break;
                    case 3: constantName = "WARN"; break;
                    case 4: constantName = "ERROR"; break;
                    default: constantName = "DEBUG"; break;
                }

                // Replace the integer value with the enum constant reference
                annotation.setValue("value", "com.jcabi.aspects.Loggable." + constantName);
            }
        } catch (Exception e) {
            // Silently ignore errors in processing - just continue
            // This ensures the transformation doesn't fail on unexpected patterns
        }
    }
}

